import numpy as np

# {The algorithm selects the next node based on dynamic node attractiveness scores that weigh distance, congestion, and estimated future importance, updating scores dynamically as the routes progress.}
def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node

    node_attractiveness_scores = {}

    for node in unvisited_nodes:
        distance_score = distance_matrix[current_node, node]
        congestion_score = np.mean([np.exp(-distance_matrix[truck, node]) for truck in truck_nodes])
        future_importance_score = 1 / (1 + np.var([distance_matrix[truck, node] for truck in truck_nodes]))

        node_attractiveness_scores[node] = distance_score + congestion_score + future_importance_score

    next_node = min(node_attractiveness_scores, key=node_attractiveness_scores.get)

    return next_node
